var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"제가… 태양문을 지키게 된다고요?","JPN":"私が……太陽の門を守るのですか？","ENG":"I'm... going to guard the Solar Gate?","TWN":"要我…守護太陽門嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"그렇습니다. 엘리시온의 심장과도 같은 성역을 지키는 아주 영예로운 일이죠.","JPN":"そうです。エリシオンの心臓ともいえる聖域を守る、とても名誉あることですよ。","ENG":"Yes. It is an honorable task to guard the sanctuary that is the heart of Elysion.","TWN":"是的。守護艾利森心臟般的聖域，這是非常光榮的任務。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"태양문의 위병으로서 주어진 기간을 무사히 복무한다면, 정식 팔라딘의 자격을 갖추게 될 겁니다.","JPN":"太陽の門の衛兵として与えられた期間に無事服役が終わると、正式パラディンの資格を得ることになります。","ENG":"Once you fulfill your time as the guard of the Solar Gate, you will officially become a paladin.","TWN":"作為太陽門的衛兵，如果能順利渡過規定的服役期，就能獲得正式聖騎士的資格。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"우와아…","JPN":"うわあ……","ENG":"Wow...","TWN":"哇喔…"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"꿈만 같아요. 드디어 제가 에클레시아님 같은 팔라딘이 된다니…","JPN":"夢みたいです。ようやく私がエクレシア様のようなパラディンになるなんて……","ENG":"It's like I'm dreaming. I can finally become a paladin like Her Eminence...","TWN":"簡直像做夢一樣，我終於也能成為像艾克蕾西亞主教那樣的聖騎士了…"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"이런 기회를 주셔서 감사합니다! 교구장님!","JPN":"こんな機会をくださって、ありがとうございます！　教区長！","ENG":"Thank you for this opportunity, sir!","TWN":"謝謝教區主教給我這個機會！！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"저에게 감사하지 않아도 됩니다.","JPN":"私に感謝する必要はありません。","ENG":"There is no need to thank me.","TWN":"不用特別感謝我。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"이건 제가 아니라 에클레시아님께서 특별히 부탁하신 일이니까요.","JPN":"これは私ではなく、エクレシア様から特別に頼まれたことですから。","ENG":"This was a special request from Her Eminence.","TWN":"這是艾可露西亞主教特別拜託的事情。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"아앗… 정말요?!","JPN":"わあっ……本当ですか！？","ENG":"Oh... really?!","TWN":"真…真的嗎？！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"다들 똑같이 노력했는데… 저 혼자만 이런 특혜를 누려도 괜찮은 걸까요?","JPN":"みんな一緒に頑張ったのに……私だけこんなに恵まれてもいいのでしょうか？","ENG":"But we all worked so hard... Will it be okay for me to be the only one with these kinds of privileges?","TWN":"大家都一樣努力…只有我一個人享受這樣的特權，真的可以嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"공정성을 위해 본인이 직접 추천을 철회하겠다면 막을 의사는 없습니다만…","JPN":"公正性のため、あなたが自ら推薦を撤回するというなら止める気はありませんが……","ENG":"If you wish to refuse this position out of fairness, I will not stop you, but...","TWN":"公平起見，如果你要拒絕這項任務，我也不會阻止…"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"네? 아뇨! 그럴 리가요!","JPN":"はい？　いいえ！　そんな！","ENG":"Huh? No! Of course I wouldn't!","TWN":"呃？不！怎麼會呢！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"쓸데없는 소릴 해서 죄송합니다!","JPN":"余計なことを言って申し訳ありません！","ENG":"I'm sorry for talking nonsense!","TWN":"我好像多嘴了，很抱歉！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"하하, 걱정마세요. 당신의 출중한 실력은 다들 인정하고 있으니까요.","JPN":"はは、心配しないでください。あなたの素晴らしい実力は、皆から認められています。","ENG":"Haha, no worries. Everyone recognizes your outstanding skills.","TWN":"哈哈，別擔心，大家都認可你出色的能力。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"언젠가 훌륭한 팔라딘이 되겠지만, 그 시기가 좀 더 앞당겨졌을 뿐입니다.","JPN":"いつか立派なパラディンになるでしょうが、その時期が少し早くなっただけです。","ENG":"You will become a great paladin one day, and the only thing that has changed is that your time has come a little earlier.","TWN":"你總有一天會成為傑出的聖騎士，現在只是把時間提前而已。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"앞당겨진 거라고요?","JPN":"早くなった？","ENG":"A little earlier?","TWN":"提前嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"동토의 역병이 날로 짙어지고 있어요.","JPN":"凍土の疫病が日に日にひどくなっています。","ENG":"The plague of the gelid lands is getting worse day by day.","TWN":"凍土的瘟疫日益嚴重。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"추기경들 사이에선 마왕을 서둘러 토벌해야 한다는 우려의 목소리가 날로 커져가고 있죠.","JPN":"枢機卿の間では、早急に魔王を討伐しなければという焦りの声も上がっています。","ENG":"The cardinals' concerns have grown larger and they wish to eliminate the Demon Lord as fast as possible.","TWN":"樞機主教之間，急需討伐魔王的呼聲越來越高。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"에클레시아님께선, 모드레드 자매님이 마왕 토벌에 일조하길 바라고 계시는 겁니다.","JPN":"エクレシア様は、シスターモードレッドが魔王の討伐に携わることをお望みなのです。","ENG":"Her Eminence seems to want your help in defeating the Demon Lord, Sister Mordred.","TWN":"艾可露西亞主教希望莫德雷德姐妹能在討伐魔王中有所貢獻。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"에클레시아님이… 저를…?","JPN":"エクレシア様が……私を……？","ENG":"Her Eminence... wants me...?","TWN":"艾可露西亞主教…希望我…？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"일주일 뒤, 위병교대식을 치르고 첫 근무를 서게 될 겁니다.","JPN":"一週間後、衛兵交代式を経て初勤務につくことになるでしょう。","ENG":"In a week, you will begin your first shift as the guard of the Solar Gate after the guard changing ceremony.","TWN":"一週後，將舉行衛兵交接儀式，你將開始第一次值勤。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"그러니 그 전까지 몸가짐을 바르게 하시길.","JPN":"ですから、それまで言動に気をつけてください。","ENG":"Until then, I suggest you behave yourself.","TWN":"所以在那之前，請保持端正的行為舉止。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"네, 명심하겠습니다.","JPN":"はい、肝に銘じます。","ENG":"I'll keep that in mind, sir.","TWN":"是！我明白了！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"아 참.","JPN":"あ、そうだ。","ENG":"Oh, right.","TWN":"對了。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"교대식 전에 태양문을 답사하고 싶은데, 괜찮을까요?","JPN":"交代式の前に太陽の門を調査したいのですが、大丈夫でしょうか？","ENG":"Would it be okay for me to tour the Solar Gate before the ceremony?","TWN":"我想在交接儀式前勘察太陽門，可以嗎？"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"그럼 함께 가지요. 분명 좋은 경험이 될 겁니다.","JPN":"それでは、ご一緒します。きっといい経験になるでしょう。","ENG":"I shall be your guide. I am certain it will be a good experience for you.","TWN":"那就一起去吧。這一定會是一次很好的經歷。"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"네! 잘 부탁드려요!","JPN":"はい！　よろしくお願いします！","ENG":"Okay! Thank you!","TWN":"是！拜託了！"},"stage":{"bg":"SKY_SUNSET","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};